from pathlib import Path
from subprocess import check_output

def rc(seq):
    comp=str.maketrans('acgtACGT','tgcaTGCA')
    return seq.translate(comp)[::-1]

def tm(seq):
    out=check_output(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',seq], text=True).strip()
    return float(out)
text=Path('/app/sequences.fasta').read_text().splitlines()
seqs={}
name=None
for line in text:
    line=line.strip()
    if not line: continue
    if line.startswith('>'):
        name=line[1:]
        seqs[name]=''
    else:
        seqs[name]+=line
inp=seqs['input']
out=seqs['output']
p=0
while p<min(len(inp),len(out)) and inp[p]==out[p]: p+=1
s=0
while s<min(len(inp)-p,len(out)-p) and inp[-1-s]==out[-1-s]: s+=1
insert=out[p:len(out)-s]
assert inp[:p]==out[:p]
assert inp[p:]==out[p+len(insert):]
left_all=inp[:p]
right_all=inp[p:]
cands=[]
for lr in range(15,46):
    annealed_rev = left_all[-lr:]
    rev_anneal_primer = rc(annealed_rev)
    tmr = tm(rev_anneal_primer)
    if not (58 <= tmr <= 72):
        continue
    for lf in range(15,46):
        annealed_fwd = right_all[:lf]
        tmf = tm(annealed_fwd)
        if not (58 <= tmf <= 72):
            continue
        if abs(tmf-tmr) > 5:
            continue
        for k in range(len(insert)+1):
            fwd = insert[k:] + annealed_fwd
            rev = rc(annealed_rev + insert[:k])
            concat = rc(rev) + fwd
            i = concat.find(insert)
            if i < 0:
                continue
            ir = concat[:i]
            iff = concat[i+len(insert):]
            if ir != annealed_rev or iff != annealed_fwd:
                continue
            if not (15 <= len(ir) <= 45 and 15 <= len(iff) <= 45):
                continue
            if inp[:p] + insert + inp[p:] != out:
                continue
            cands.append((abs(tmf-tmr), len(fwd)+len(rev), max(len(fwd),len(rev)), k, lr, lf, tmf, tmr, fwd, rev))
cands.sort()
print('num_candidates', len(cands))
for c in cands[:40]:
    diff,total,mx,k,lr,lf,tmf,tmr,fwd,rev = c
    print({'k':k,'lr':lr,'lf':lf,'tmf':round(tmf,2),'tmr':round(tmr,2),'diff':round(diff,2),'total':total,'max':mx,'fwd':fwd,'rev':rev})
